import{_ as t,c as e,o as r,d as a}from"./app.564110b9.js";const d=JSON.parse('{"title":"\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177","description":"","frontmatter":{},"headers":[],"relativePath":"Document/DevDebug/\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177.md","lastUpdated":1661248786000}'),p={name:"Document/DevDebug/\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177.md"},o=a('<h1 id="\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177" tabindex="-1">\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177 <a class="header-anchor" href="#\u5176\u4ED6\u8C03\u8BD5\u5DE5\u5177" aria-hidden="true">#</a></h1><p>Postman\u3001Apifox\u3001ApiPost</p><p>\u5730\u5740\uFF1A<a href="http://www.postman.com/" target="_blank" rel="noreferrer">www.postman.com/</a></p><p>\u51E0\u4E4E\u6240\u6709\u524D\u7AEF\u5E94\u7528\u7A0B\u5E8F\u90FD\u53D1\u9001\u548C\u63A5\u6536JSON\u54CD\u5E94\u548C\u8BF7\u6C42\u3002 \u5E94\u7528\u7A0B\u5E8F\u901A\u8FC7\u8BF7\u6C42 API \u53EF\u4EE5\u505A\u5F88\u591A\u4E8B\u60C5\uFF0C\u4F8B\u5982\u8EAB\u4EFD\u9A8C\u8BC1\uFF0C\u7528\u6237\u6570\u636E\u4F20\u8F93\uFF0C\u751A\u81F3\u662F\u4E00\u4E9B\u7B80\u5355\u7684\u4E8B\u60C5\uFF0C\u4F8B\u5982\u83B7\u53D6\u6240\u5728\u4F4D\u7F6E\u7684\u5F53\u524D\u5929\u6C14\u3002</p><p>Postman \u662F\u8C03\u8BD5\u63A5\u53E3\u7684\u6700\u4F73\u5DE5\u5177\u4E4B\u4E00\u3002 \u5B83\u9002\u7528\u4E8E MacOS\uFF0CWindows \u548CLinux\u7684\u7CFB\u7EDF\uFF0C \u53EF\u4EE5\u5FEB\u901F\u8F7B\u677E\u5730\u76F4\u63A5\u53D1\u9001REST\uFF0CSOAP\u548CGraphQL\u8BF7\u6C42\u3002</p><p>\u4F7F\u7528 Postman\uFF0C\u6211\u4EEC\u53EF\u4EE5\u8C03\u6574\u8BF7\u6C42\uFF0C\u5206\u6790\u54CD\u5E94\u548C\u8C03\u8BD5\u95EE\u9898\u3002 \u5F53\u4E0D\u786E\u5B9A\u95EE\u9898\u51FA\u5728\u524D\u7AEF\u8FD8\u662F\u540E\u7AEF\u65F6\uFF0C\u8FD9\u662F\u5F88\u6709\u5E2E\u52A9\u7684\u3002</p><p>\u6D4F\u89C8\u5668\u590D\u5236cUrl\u5230\u5DE5\u5177\u7C98\u8D34\u8BF7\u6C42</p><p>CSS Lint</p><p>\u5730\u5740\uFF1A <a href="http://csslint.net/" target="_blank" rel="noreferrer">csslint.net/</a></p><p>CSSLint \u662F\u4E00\u4E2A\u7528\u6765\u5E2E\u4F60\u627E\u51FA CSS \u4EE3\u7801\u4E2D\u95EE\u9898\u7684\u5DE5\u5177\uFF0C\u5B83\u53EF\u505A\u57FA\u672C\u7684\u8BED\u6CD5\u68C0\u67E5\u4EE5\u53CA\u4F7F\u7528\u4E00\u5957\u9884\u8BBE\u7684\u89C4\u5219\u6765\u68C0\u67E5\u4EE3\u7801\u4E2D\u7684\u95EE\u9898\uFF0C\u89C4\u5219\u662F\u53EF\u4EE5\u6269\u5C55\u7684\u3002</p><p>JSON Formatter &amp; Validator</p><p>\u5730\u5740\uFF1A<a href="http://jsonformatter.curiousconcept.com/" target="_blank" rel="noreferrer">jsonformatter.curiousconcept.com/</a></p><p>\u5728\u672A\u683C\u5F0F\u5316\u7684 JSON \u4E2D\u5F88\u96BE\u53D1\u73B0\u8BED\u6CD5\u9519\u8BEF\u6216\u952E\u503C\u4E0D\u6B63\u786E\u7684\u952E\uFF0C\u56E0\u4E3A\u5B83\u5F88\u96BE\u8BFB\u53D6\u3002 \u5BF9\u4E8E \u538B\u7F29\u7684 JSON \u6587\u4EF6\uFF0C\u8981\u53D1\u73B0\u5176\u4E2D\u7684\u9519\u8BEF\u662F\u6BD4\u8F83\u96BE\u7684\uFF0C\u6240\u4EE5\u6211\u4EEC\u9700\u8981\u4E00\u79CD\u683C\u5F0F\u5316\u7684\u5DE5\u5177\u3002</p><p>JSON Formatter &amp; Validator tool \u5C31\u662F\u4E00\u4E2A\u683C\u5F0F\u5316 JSON \u7684\u5DE5\u5177\uFF0C\u53EA\u9700\u8F93\u5165\u538B\u7F29\u7684JSON\u683C\u5F0F\uFF0C\u5C31\u80FD\u83B7\u5F97\u6B63\u786E\u683C\u5F0F\u3002\u8BE5\u5DE5\u5177\u4E5F\u53EF\u4EE5\u9A8C\u8BC1 JSON \u5230 RFC \u6807\u51C6\u3002</p><p>Sentry</p><p>\u5730\u5740\uFF1A<a href="http://sentry.io/welcome/" target="_blank" rel="noreferrer">sentry.io/welcome/</a></p><p>\u65E0\u8BBA\u6D4B\u8BD5\u5982\u4F55\u5B8C\u5584\u7684\u7A0B\u5E8F\uFF0Cbug\u603B\u662F\u514D\u4E0D\u4E86\u4F1A\u5B58\u5728\u7684\uFF0C\u6709\u4E9Bbug\u4E0D\u662F\u6BCF\u6B21\u90FD\u4F1A\u51FA\u73B0\uFF0C\u6D4B\u8BD5\u65F6\u8FD0\u884C\u597D\u597D\u7684\u4EE3\u7801\u53EF\u80FD\u5728\u67D0\u4E2A\u7528\u6237\u4F7F\u7528\u65F6\u5C31\u6B47\u83DC\u4E86\uFF0C\u53EF\u662F\u5F53\u7A0B\u5E8F\u5728\u7528\u6237\u9762\u524D\u5D29\u6E83\u65F6\uFF0C\u4F60\u662F\u770B\u4E0D\u5230\u9519\u8BEF\u7684\uFF0C\u5F53\u7136\u4F60\u4F1A\u8BF4:\u201DHey, \u6211\u6709\u8BB0\u65E5\u5FD7\u5462\u201D\u3002 \u4F46\u662F\u8BF4\u5B9E\u8BDD\uFF0C\u7A0B\u5E8F\u6BCF\u5929\u6BCF\u65F6\u90FD\u5728\u4EA7\u751F\u5927\u91CF\u7684\u65E5\u5FD7\uFF0C\u800C\u4E14\u5206\u5E03\u5728\u5404\u4E2A\u670D\u52A1\u5668\u4E0A\uFF0C\u5E76\u4E14\u5982\u679C\u4F60\u6709\u591A\u4E2A\u670D\u52A1\u5728\u7EF4\u62A4\u7684\u8BDD\uFF0C\u65E5\u5FD7\u7684\u6570\u91CF\u4E4B\u591A\u4F60\u662F\u770B\u4E0D\u8FC7\u6765\u7684\u5427\u3002\u7B49\u5230\u67D0\u5929\u67D0\u4E2A\u7528\u6237\u5B9E\u5728\u53D7\u4E0D\u4E86\u4E86\uFF0C\u6253\u7535\u8BDD\u6765\u5486\u54EE\u7684\u65F6\u5019\uFF0C\u4F60\u518D\u53BB\u627E\u65E5\u5FD7\u4F60\u53C8\u4F1A\u53D1\u73B0\u65E5\u5FD7\u5176\u5B9E\u6CA1\u4EC0\u4E48\u7528\uFF1A\u7F3A\u5C11\u4E0A\u4E0B\u6587\uFF0C\u4E0D\u77E5\u9053\u7528\u6237\u4EC0\u4E48\u64CD\u4F5C\u5BFC\u81F4\u7684\u5F02\u5E38\uFF0C\u5F02\u5E38\u592A\u591A\uFF08\u4ECE\u4E0D\u770B\u65E5\u5FD7\u7684\u7F18\u6545\uFF09\u4E0D\u77E5\u5982\u4F55\u4E0B\u624B \u7B49\u7B49\u3002</p><p>Sentry\u5C31\u662F\u6765\u5E2E\u6211\u4EEC\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u7684\uFF0C\u5B83\u662F\u662F\u4E00\u4E2A\u5B9E\u65F6\u4E8B\u4EF6\u65E5\u5FD7\u8BB0\u5F55\u548C\u805A\u5408\u5E73\u53F0\u3002\u5B83\u4E13\u95E8\u7528\u4E8E\u76D1\u89C6\u9519\u8BEF\u548C\u63D0\u53D6\u6267\u884C\u9002\u5F53\u7684\u4E8B\u540E\u64CD\u4F5C\u6240\u9700\u7684\u6240\u6709\u4FE1\u606F, \u800C\u65E0\u9700\u4F7F\u7528\u6807\u51C6\u7528\u6237\u53CD\u9988\u5FAA\u73AF\u7684\u4EFB\u4F55\u9EBB\u70E6\u3002 Sentry\u662F\u4E00\u4E2A\u65E5\u5FD7\u5E73\u53F0, \u5B83\u5206\u4E3A\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u7AEF\uFF0C\u5BA2\u6237\u7AEF(\u76EE\u524D\u5BA2\u6237\u7AEF\u6709Python, PHP,C#, Ruby\u7B49\u591A\u79CD\u8BED\u8A00)\u5C31\u5D4C\u5165\u5728\u4F60\u7684\u5E94\u7528\u7A0B\u5E8F\u4E2D\u95F4\uFF0C\u7A0B\u5E8F\u51FA\u73B0\u5F02\u5E38\u5C31\u5411\u670D\u52A1\u7AEF\u53D1\u9001\u6D88\u606F\uFF0C\u670D\u52A1\u7AEF\u5C06\u6D88\u606F\u8BB0\u5F55\u5230\u6570\u636E\u5E93\u4E2D\u5E76\u63D0\u4F9B\u4E00\u4E2Aweb\u8282\u76EE\u65B9\u4FBF\u67E5\u770B\u3002Sentry \u7531 python \u7F16\u5199\uFF0C\u6E90\u7801\u5F00\u653E\uFF0C\u6027\u80FD\u5353\u8D8A\uFF0C\u6613\u4E8E\u6269\u5C55\uFF0C\u76EE\u524D\u8457\u540D\u7684\u7528\u6237\u6709Disqus, Path, mozilla, Pinterest\u7B49\u3002</p><p>JSHint</p><p>\u5730\u5740\uFF1A<a href="http://jshint.com/" target="_blank" rel="noreferrer">jshint.com/</a></p><p>JSHint \u662F\u4E00\u4E2A Javascript \u4EE3\u7801\u5206\u6790\u68C0\u6D4B\u5DE5\u5177\uFF0C\u4E0D\u4EC5\u53EF\u4EE5\u5E2E\u52A9\u6211\u4EEC\u68C0\u6D4B\u5230 JS \u4EE3\u7801\u9519\u8BEF\u548C\u6F5C\u5728\u95EE\u9898\uFF0C\u4E5F\u80FD\u5E2E\u52A9\u6211\u4EEC\u89C4\u8303\u4EE3\u7801\u5F00\u53D1\u3002</p><p>JSHint \u626B\u63CF\u4E00\u4E2A\u7528JavaScript\u7F16\u5199\u7684\u7A0B\u5E8F\uFF0C\u5E76\u62A5\u544A\u5E38\u89C1\u7684\u9519\u8BEF\u548C\u6F5C\u5728\u7684bug\u3002\u6F5C\u5728\u7684\u95EE\u9898\u53EF\u80FD\u662F\u8BED\u6CD5\u9519\u8BEF\u3001\u9690\u5F0F\u7C7B\u578B\u8F6C\u6362\u5BFC\u81F4\u7684\u9519\u8BEF\u3001\u6CC4\u6F0F\u53D8\u91CF\u6216\u5176\u4ED6\u5B8C\u5168\u7684\u95EE\u9898\u3002</p><p>JSHint \u626B\u63CF\u7528 JavaScript \u7F16\u5199\u7684\u7A0B\u5E8F\uFF0C\u5E76\u62A5\u544A\u5E38\u89C1\u7684\u9519\u8BEF\u548C\u6F5C\u5728\u7684\u9519\u8BEF\u3002 \u6F5C\u5728\u7684\u95EE\u9898\u53EF\u80FD\u662F\u8BED\u6CD5\u9519\u8BEF\uFF0C\u7531\u4E8E\u9690\u5F0F\u7C7B\u578B\u8F6C\u6362\u5BFC\u81F4\u7684\u9519\u8BEF\uFF0C\u53D8\u91CF\u6CC4\u6F0F\u6216\u5176\u4ED6\u5B8C\u5168\u539F\u56E0\u3002</p><p>\u4E0B\u9762\u662F\u4E00\u4E2A\u793A\u4F8B\u51FD\u6570\uFF0C\u4F7F\u7528\u5B83\u6765\u67E5\u770B JSHint \u7684\u8FD0\u884C\u60C5\u51B5:</p><p>BrowserStack</p><p>\u5730\u5740\uFF1A<a href="http://www.browserstack.com/" target="_blank" rel="noreferrer">www.browserstack.com/</a></p><p>\u73B0\u5728\u62E5\u6709\u5404\u81EA\u5185\u6838\u7684\u6D4F\u89C8\u5668\u8D8A\u6765\u8D8A\u591A\uFF0C\u5404\u81EA\u7684\u7279\u6027\u4E5F\u5343\u5DEE\u4E07\u522B\u3002\u5982\u679C\u4F5C\u4E3A\u4E00\u4E2A\u524D\u7AEF\u653B\u57CE\u5E08\u60F3\u8981\u68C0\u6D4B\u7F51\u7AD9\u5728\u4E0D\u540C\u7684\u64CD\u4F5C\u7CFB\u7EDF\u548C\u79FB\u52A8\u5E73\u53F0\u4E0B\u7684\u5404\u79CD\u6D4F\u89C8\u5668\u7684\u517C\u5BB9\u6027\uFF0C\u90A3\u662F\u76F8\u5F53\u75DB\u82E6\u4E0D\u582A\u7684\u3002\u770B\u5230\u6709\u5728\u81EA\u5DF1\u7535\u8111\u4E0A\u88C5\u865A\u62DF\u673A\u914D\u7F6E\u5404\u79CD\u73AF\u5883\uFF0C\u6709\u81EA\u5DF1\u7684\u7535\u8111\u4E0A\u7EC4\u5EFA\u597D\u8FD9\u6837\u7684\u73AF\u5883\uFF0C\u7136\u540E\u4E00\u4E00\u6D4B\u8BD5\uFF0C\u53EF\u662F\u4EBA\u7684\u7CBE\u529B\u6BD5\u7ADF\u6709\u9650\uFF0C\u6211\u4EEC\u6CA1\u6CD5\u5728\u540C\u4E00\u53F0\u7535\u8111\u4E0A\u88C5\u90A3\u4E48\u591A\u7CFB\u7EDF\uFF0C\u90A3\u4E48\u591A\u6D4F\u89C8\u5668\u7684\u3002\u5E78\u597D\u51FA\u4E86\u4E2A BrowserStack \u662F\u524D\u7AEF\u7684\u798F\u97F3\u5440\u3002</p><p>BrowserStack \u662F\u4E00\u6B3E\u63D0\u4F9B\u7F51\u7AD9\u6D4F\u89C8\u5668\u517C\u5BB9\u6027\u6D4B\u8BD5\u7684\u5728\u7EBF\u4E91\u7AEF\u6D4B\u8BD5\u5DE5\u5177\uFF0C\u4ECE\u800C\u5F00\u53D1\u6D4B\u8BD5\u4EBA\u5458\u4E0D\u5FC5\u518D\u51C6\u5907\u5F88\u591A\u865A\u62DF\u673A\u6216\u8005\u624B\u673A\u6A21\u62DF\u5668\u3002</p><p>BrowserStack \u662F\u4E00\u4E2A\u63D0\u4F9B\u7F51\u7AD9\u6D4F\u89C8\u5668\u517C\u5BB9\u6027\u6D4B\u8BD5\u7684\u5728\u7EBF\u4E91\u7AEF\u5E94\u7528\uFF0C\u652F\u63019\u5927\u64CD\u4F5C\u7CFB\u7EDF\u4E0A\u7684100\u591A\u6B3E\u6D4F\u89C8\u5668\u3002\u652F\u6301\u672C\u5730\u6D4B\u8BD5\uFF0C\u652F\u6301\u4E0EVisual Studio\u96C6\u6210\u3002\u6216\u8005\u4F60\u4E5F\u53EF\u4EE5\u76F4\u63A5\u524D\u5F80 <a href="http://modern.ie" target="_blank" rel="noreferrer">modern.ie</a> \u5728\u7EBF\u6D4B\u8BD5\uFF0C\u73B0\u5728\u6CE8\u518C\u53EF\u4EE5\u514D\u8D39\u8BD5\u7528\u4E09\u4E2A\u6708\uFF0C\u4E09\u4E2A\u6708\u540E\u662F\u6536\u8D39\u7684\uFF0C\u4E09\u4E2A\u6708\u540E\u8981\u662F\u4F60\u60F3\u7528\u53C8\u4E0D\u60F3\u4ED8\u8D39\u4F5C\u4E3A\u5929\u671D\u7684\u5F00\u53D1\u8005\u4F60\u61C2\u5F97\u3002</p>',29),n=[o];function s(c,i,_,S,l,m){return r(),e("div",null,n)}const f=t(p,[["render",s]]);export{d as __pageData,f as default}